import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int maxLength = Math.min(userInput.length(), 10); // Limit the input length to 10 characters

        char[] buffer = new char[10];

        // Copy the user input into the buffer with boundary checking
        for (int i = 0; i < maxLength; i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer content: " + String.valueOf(buffer));
    }
}

